module SR_latch(  
    input wire Invalid_S,  
    input wire R,  
    output reg Q,  
    output reg Qn  
);  
    always @ (Invalid_S, R) begin  
        if (Invalid_S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end  
        else if (!Invalid_S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end  
        // Invalid condition: Invalid_S=1, R=1
        // Maintain the previous state (no change)
    end  
endmodule
